import React, { createContext, useState, useEffect } from 'react';
import axios from 'axios';

const BACKEND_URL = process.env.REACT_APP_BACKEND_URL;

export const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);
    const [token, setToken] = useState(localStorage.getItem('authToken'));

    // Configure axios defaults
    useEffect(() => {
        if (token) {
            axios.defaults.headers.common['Authorization'] = `Bearer ${token}`;
        } else {
            delete axios.defaults.headers.common['Authorization'];
        }
    }, [token]);

    // Check if user is authenticated
    const isAuthenticated = () => {
        return !!token && !!user;
    };

    // Login with Google
    const loginWithGoogle = async (credential) => {
        try {
            const response = await axios.post(`${BACKEND_URL}/api/auth/google/verify`, {
                credential: credential
            });

            const { access_token, user: userData } = response.data;

            // Store token and user data
            localStorage.setItem('authToken', access_token);
            setToken(access_token);
            setUser({...userData, token: access_token});

            return { success: true };
        } catch (error) {
            console.error('Google login failed:', error);
            return {
                success: false,
                error: error.response?.data?.detail || '–ù–µ —É–¥–∞–ª–æ—Å—å –≤–æ–π—Ç–∏'
            };
        }
    };

    // Login with Telegram
    const loginWithTelegram = async (telegramUser) => {
        try {
            const response = await axios.post(`${BACKEND_URL}/api/auth/telegram/verify`, {
                telegram_user: telegramUser
            });

            const { access_token, user: userData } = response.data;

            // Store token and user data
            localStorage.setItem('authToken', access_token);
            setToken(access_token);
            setUser({...userData, token: access_token});

            return { success: true };
        } catch (error) {
            console.error('Telegram login failed:', error);
            return {
                success: false,
                error: error.response?.data?.detail || '–ù–µ —É–¥–∞–ª–æ—Å—å –≤–æ–π—Ç–∏ —á–µ—Ä–µ–∑ Telegram'
            };
        }
    };

    // Logout
    const logout = () => {
        localStorage.removeItem('authToken');
        setToken(null);
        setUser(null);
        delete axios.defaults.headers.common['Authorization'];
    };

    // Get user profile
    const fetchUserProfile = async () => {
        try {
            if (!token) return;

            const response = await axios.get(`${BACKEND_URL}/api/profile`);
            setUser({...response.data, token: token});
        } catch (error) {
            console.error('Failed to fetch user profile:', error);
            if (error.response?.status === 401) {
                logout();
            }
        }
    };

    // Update user profile
    const updateProfile = async (data) => {
        try {
            const response = await axios.put(`${BACKEND_URL}/api/profile`, data);
            setUser(response.data);
            return { success: true };
        } catch (error) {
            console.error('Failed to update profile:', error);
            return {
                success: false,
                error: error.response?.data?.detail || '–ù–µ —É–¥–∞–ª–æ—Å—å –æ–±–Ω–æ–≤–∏—Ç—å –ø—Ä–æ—Ñ–∏–ª—å'
            };
        }
    };

    // Save API keys
    const saveApiKeys = async (apiKeys) => {
        try {
            const response = await axios.post(`${BACKEND_URL}/api/api-keys`, apiKeys);

            // Update user object
            setUser(prev => ({ 
                ...prev, 
                has_api_key_1: !!(apiKeys.api_key_1 || prev.has_api_key_1),
                has_api_key_2: !!(apiKeys.api_key_2 || prev.has_api_key_2),
                has_api_key_3: !!(apiKeys.api_key_3 || prev.has_api_key_3)
            }));

            return { success: true, message: response.data.message };
        } catch (error) {
            console.error('Failed to save API keys:', error);
            return {
                success: false,
                error: error.response?.data?.detail || '–ù–µ —É–¥–∞–ª–æ—Å—å —Å–æ—Ö—Ä–∞–Ω–∏—Ç—å API –∫–ª—é—á–∏'
            };
        }
    };

    // Save Gemini API key (quick setup)
    const saveGeminiApiKey = async (apiKey) => {
        try {
            const response = await axios.post(`${BACKEND_URL}/api/quick-gemini-setup`, {
                api_key: apiKey
            });

            // –ù–µ–º–µ–¥–ª–µ–Ω–Ω–æ –æ–±–Ω–æ–≤–ª—è–µ–º —Å–æ—Å—Ç–æ—è–Ω–∏–µ –ø–æ–ª—å–∑–æ–≤–∞—Ç–µ–ª—è
            setUser(prev => ({ 
                ...prev, 
                has_gemini_api_key: true,
                has_api_key_1: true // –¢–∞–∫–∂–µ –æ–±–Ω–æ–≤–ª—è–µ–º –¥–ª—è —Å–æ–≤–º–µ—Å—Ç–∏–º–æ—Å—Ç–∏
            }));

            // –ù–ï –≤—ã–∑—ã–≤–∞–µ–º fetchUserProfile(), —á—Ç–æ–±—ã –Ω–µ –ø–µ—Ä–µ–∑–∞–ø–∏—Å–∞—Ç—å –æ–ø—Ç–∏–º–∏—Å—Ç–∏—á–Ω–æ–µ –æ–±–Ω–æ–≤–ª–µ–Ω–∏–µ
            // –ü—Ä–æ—Ñ–∏–ª—å –æ–±–Ω–æ–≤–∏—Ç—Å—è –ø—Ä–∏ —Å–ª–µ–¥—É—é—â–µ–π –µ—Å—Ç–µ—Å—Ç–≤–µ–Ω–Ω–æ–π –ø–µ—Ä–µ–∑–∞–≥—Ä—É–∑–∫–µ

            return { success: true, message: response.data.message };
        } catch (error) {
            console.error('Failed to save Gemini API key:', error);
            return {
                success: false,
                error: error.response?.data?.detail || '–ù–µ —É–¥–∞–ª–æ—Å—å —Å–æ—Ö—Ä–∞–Ω–∏—Ç—å API –∫–ª—é—á'
            };
        }
    };

    // Initialize authentication state
    useEffect(() => {
        const initAuth = async () => {
            if (token) {
                await fetchUserProfile();
            }
            setLoading(false);
        };

        initAuth();
    }, [token]);

    // Update user language
    const updateUserLanguage = async (language) => {
        try {
            const response = await axios.post(`${BACKEND_URL}/api/change-language`, {
                language: language
            });

            // –û–±–Ω–æ–≤–ª—è–µ–º —Å–æ—Å—Ç–æ—è–Ω–∏–µ –ø–æ–ª—å–∑–æ–≤–∞—Ç–µ–ª—è
            setUser(prev => ({ 
                ...prev, 
                preferred_language: language
            }));

            return { success: true, message: response.data.message };
        } catch (error) {
            console.error('Failed to update language:', error);
            return {
                success: false,
                error: error.response?.data?.detail || '–ù–µ —É–¥–∞–ª–æ—Å—å –æ–±–Ω–æ–≤–∏—Ç—å —è–∑—ã–∫'
            };
        }
    };

    const value = {
        user,
        token,
        loading,
        isAuthenticated,
        loginWithGoogle,
        loginWithTelegram,
        logout,
        fetchUserProfile,
        updateProfile,
        saveApiKeys,
        saveGeminiApiKey,
        updateUserLanguage
    };

    return (
        <AuthContext.Provider value={value}>
            {children}
        </AuthContext.Provider>
    );
};
